SELECT country_code, AVG(contribution_percentage) AS average_contribution
FROM country_industries
GROUP BY country_code;

SELECT SUM(net_value) AS total_net_value
FROM net_values
WHERE country_code = 'A' AND year = 2020;

SELECT country_name, capital_city 
FROM countries 
WHERE country_code = 'US';

SELECT industry_id, COUNT(*) as industry_count
FROM industry_sectors
GROUP BY industry_id;

SELECT industry_name, industry_description 
FROM industries 
WHERE industry_id IN (SELECT industry_id FROM industry_indicators WHERE is_primary = 1);

SELECT sector_id, indicator_id
FROM sector_indicators
WHERE sector_id = 0 AND indicator_id = 0;

SELECT user_name, ROW_NUMBER() OVER (ORDER BY user_name) AS RowNum
FROM users
WHERE role = 'data analyst';

SELECT year, net_value, source
FROM net_values
WHERE country_code = '0' AND industry_id = '0';
